return items.map(item => {
  let text = item.json.output;

  if (!text) {
    return { json: { ...item.json, error: "No output text found" } };
  }

  // 1. Clean markdown code blocks and wrapper quotes
  text = text.trim();
  text = text.replace(/^```json\s*/i, "");
  text = text.replace(/\s*```$/i, "");
  text = text.replace(/^"?json\s*/i, "");
  text = text.trim();

  // 2. Handle cases where the JSON itself is wrapped inside a string
  if (text.startsWith('"') && text.endsWith('"')) {
    try {
      text = JSON.parse(text);
    } catch (e) {
      // If parsing fails, fall back to stripping the wrapping quotes manually
      text = text.slice(1, -1);
    }
  }

  // 3. Final Parse with a fallback in case the LLM cut off the response mid-sentence
  let ats = {};
  try {
    ats = JSON.parse(text);
  } catch (parseError) {
    // Fallback: If it's cut off, try to manually patch missing closing brackets
    try {
      ats = JSON.parse(text + '}');
    } catch (nestedError) {
      try {
        ats = JSON.parse(text + ']}');
      } catch (finalError) {
        // If it's completely unparseable, return the raw text so the workflow doesn't crash
        return {
          json: {
            ...item.json,
            parsing_failed: true,
            raw_unparsed_output: text
          }
        };
      }
    }
  }

  return {
    json: {
      ...item.json,
      ...ats
    }
  };
});

